SELECT c.*, COUNT(bc.book_id) AS total_books FROM contributors c LEFT JOIN book_contributors bc ON c.id = bc.contributor_id
AND c.role = #{role}
AND c.name LIKE CONCAT('%', #{search}, '%')
GROUP BY c.id ORDER BY c.name ASC LIMIT #{limit} OFFSET #{offset}

